SELECT AVG(lifespan) AS average_lifespan
FROM animals
WHERE habitat_type = 'terrestrial' AND conservation_status = 'vulnerable';

SELECT kingdom, class_, phylum, animal_name
FROM animals
WHERE conservation_status IN ('endangered', 'vulnerable');

SELECT s.conservation_status
FROM species s
JOIN animals a ON s.species_name = a.species;

SELECT conservation_status 
FROM species 
WHERE lifespan = (SELECT MAX(lifespan) FROM species);

SELECT access_date
FROM access_logs
WHERE access_date > DATE('now', '-30 days');
